query dashboardData($startDate: DateTime!, $endDate: DateTime!) {
  membersByRegion(startDate: $startDate, endDate: $endDate) {
    child
    parent
    value
  }
  membershipShare(startDate: $startDate, endDate: $endDate) {
    name
    value
  }
  ntaMembersOverTime(startDate: $startDate, endDate: $endDate) {
    child
    parent
    value
  }
  sesnetMembersOverTime(startDate: $startDate, endDate: $endDate) {
    child
    parent
    value
  }
  totalNTAMembers(startDate: $startDate, endDate: $endDate)
  totalSesnetMembers(startDate: $startDate, endDate: $endDate)
  pendingApprovals(startDate: $startDate, endDate: $endDate)
  rejectedApplications(startDate: $startDate, endDate: $endDate)
}

893a0526512cac752df6bac30ca9fb681ec6ab4a:
mutation UpdateMemberStatus($input: UpdateMemberStatusInput) {
  updateMemberStatus(input: $input) {
    callResult {
      success
      message
      code
    }
  }
}

b77a7793ed2ca3e217d9088aa4017343076a59cc:
query Members($skip: Int, $take: Int, $filter: MemberFilterInput, $order: [MemberSortInput!]) {
  members(skip: $skip, take: $take, where: $filter, order: $order) {
    pageInfo {
      hasNextPage
      hasPreviousPage
    }
    totalCount
    items {
      additionalInformation
      address {
        rootElement
      }
      category
      commencementYear
      createdBy
      employeeDetails {
        rootElement
      }
      ghanaCardNumber
      createdOn
      description
      email
      id
      membershipDeclaration {
        rootElement
      }
      name
      operationalArea
      organization
      phoneNumber
      productMaterialCategory
      reason
      redgNo
      registeredBy {
        rootElement
      }
      revision
      status
      updatedBy
      updatedOn
    }
  }
}
